5934   }
5935 
5936   if (DT.dominates(LeftEdge, RightUse) && DT.dominates(RightEdge, LeftUse)) {
5937     LHS = RightUse;
5938     RHS = LeftUse;
5939     return true;
5940   }
5941 
5942   return false;
5943 }
