6142   // i1 cond ? i1 x : i1 C  -->  C + (i1  cond ? (i1 x - i1 C) : i1 0)
6143   //                        -->  C + (umin_seq  cond, x - C)
6144   //
6145   // i1 cond ? i1 C : i1 x  -->  C + (i1  cond ? i1 0 : (i1 x - i1 C))
6146   //                        -->  C + (i1 ~cond ? (i1 x - i1 C) : i1 0)
6147   //                        -->  C + (umin_seq ~cond, x - C)
6148 
6149   // FIXME: while we can't legally model the case where both of the hands
6150   // are fully variable, we only require that the *difference* is constant.
6151   if (!isa<SCEVConstant>(TrueExpr) && !isa<SCEVConstant>(FalseExpr))
6152     return std::nullopt;
6153 
6154   const SCEV *X, *C;
6155   if (isa<SCEVConstant>(TrueExpr)) {
6156     CondExpr = SE->getNotSCEV(CondExpr);
6157     X = FalseExpr;
6158     C = TrueExpr;
6159   } else {
6160     X = TrueExpr;
6161     C = FalseExpr;
6162   }
6163   return SE->getAddExpr(C, SE->getUMinExpr(CondExpr, SE->getMinusSCEV(X, C),
6164                                            /*Sequential=*/true));
